SELECT COUNT(DISTINCT LP.PK) AS TOTAL FROM LATTES_P_PRODBIB LPP JOIN LATTES_PRODBIB LP ON LP.PK = LPP.FK_PRODBIB JOIN SERVIDOR S ON S.PK_SIAPE = LPP.FK_SIAPE WHERE LOWER(LP.TIPO) = LOWER('trabalho em evento') AND LOWER(LP.NATUREZA) = LOWER('completo') AND TRIM(LP.ANO) = '2020' AND S.GENERO = 'FEMININO' AND S.SIGLA_CAMPUS = 'GYN' AND LOWER(COALESCE(S.AREA_INGRESSO, '')) LIKE '%letras%'